static int retry_count = 0;
#define MAX_RETRIES 5

void wifi_event_handler(void *arg, esp_event_base_t base, int32_t id, void *data) {
    if (base == WIFI_EVENT && id == WIFI_EVENT_STA_DISCONNECTED) {
        if (retry_count < MAX_RETRIES) {
            esp_wifi_connect();
            retry_count++;
        } else {
            start_ap_mode(); // fallback: open config portal
        }
    } else if (base == IP_EVENT && id == IP_EVENT_STA_GOT_IP) {
        retry_count = 0;
        // Connected — start MQTT, NTP sync, etc.
    }
}

void start_ap_mode() {
    wifi_config_t ap_config = {
        .ap = {.ssid = "MyDevice-Setup", .password = "12345678",
               .max_connection = 2, .authmode = WIFI_AUTH_WPA2_PSK}
    };
    esp_wifi_set_mode(WIFI_MODE_AP);
    esp_wifi_set_config(WIFI_IF_AP, &ap_config);
    start_captive_portal_http_server(); // serve config page
}
```

